sql:
SELECT * 
FROM benchmark_results 
WHERE solver_id = 1;

SELECT benchmark_name, difficulty_level
FROM benchmarks
WHERE created_by = 1;

SELECT benchmark_name, category_id, average_solver_time 
FROM benchmarks 
WHERE average_solver_time > (SELECT AVG(average_solver_time) FROM benchmarks);

SELECT DISTINCT s.solver_id, s.solver_name
FROM solvers s
INNER JOIN benchmark_results br ON s.solver_id = br.solver_id;

SELECT solver_id, AVG(solving_time) AS average_solving_time_per_solver
FROM benchmark_results
GROUP BY solver_id;

SELECT difficulty_level, COUNT(*) AS total
FROM benchmarks
GROUP BY difficulty_level;

SELECT benchmarks.benchmark_name, categories.category_name
   FROM benchmarks
   JOIN categories ON benchmarks.category_id = categories.category_id;

SELECT COUNT(*) AS total_successes 
FROM benchmark_results 
WHERE solver_id = 40 AND status = 'success';

